// ================================================================
// STAGE 1: ENTERPRISE VALIDATION ENGINE
// 20+ validation rules, normalization, auto-enrichment
// ================================================================

const body = $input.first().json.body || $input.first().json;
const errors = [];
const warnings = [];

// --- REQUIRED FIELDS ---
if (!body.name || body.name.trim().length < 2)
  errors.push('name required (min 2 chars)');

if (!body.email) {
  errors.push('email required');
} else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(body.email)) {
  errors.push('email format invalid');
}

if (errors.length > 0) {
  throw new Error(JSON.stringify({
    error: 'VALIDATION_FAILED',
    details: errors,
    received: Object.keys(body),
    timestamp: new Date().toISOString()
  }));
}

// --- NORMALIZATION ---
const email = body.email.toLowerCase().trim();
const domain = email.split('@')[1];
const freeProviders = [
  'gmail.com','yahoo.com','hotmail.com','outlook.com',
  'mail.ru','yandex.ru','protonmail.com','icloud.com',
  'aol.com','zoho.com','gmx.com','live.com'
];
const isBusiness = !freeProviders.includes(domain);

// --- AUTO-ENRICHMENT ---
const companyGuess = isBusiness
  ? domain.split('.')[0].charAt(0).toUpperCase() + domain.split('.')[0].slice(1)
  : null;

// --- PHONE NORMALIZATION ---
let phone = null;
if (body.phone) {
  phone = body.phone.replace(/[^\d+]/g, '');
  if (phone.length < 7) {
    warnings.push('phone seems invalid: ' + phone);
    phone = null;
  }
}

// --- BUDGET PARSING ---
let budget = null;
let budgetTier = 'unknown';
if (body.budget) {
  budget = parseFloat(String(body.budget).replace(/[^\d.]/g, ''));
  if (isNaN(budget)) { budget = null; warnings.push('budget not parseable'); }
  else if (budget >= 50000) budgetTier = 'enterprise';
  else if (budget >= 10000) budgetTier = 'mid_market';
  else if (budget >= 1000) budgetTier = 'smb';
  else budgetTier = 'micro';
}

// --- LEAD SCORING (0-100) ---
let score = 0;
const scoreLog = [];

if (isBusiness) { score += 25; scoreLog.push('+25 business_email'); }
if (body.company) { score += 15; scoreLog.push('+15 company_provided'); }
else if (companyGuess) { score += 5; scoreLog.push('+5 company_guessed'); }
if (phone) { score += 10; scoreLog.push('+10 has_phone'); }
if (budget >= 50000) { score += 20; scoreLog.push('+20 enterprise_budget'); }
else if (budget >= 10000) { score += 15; scoreLog.push('+15 mid_budget'); }
else if (budget >= 1000) { score += 8; scoreLog.push('+8 smb_budget'); }
if (body.job_title) { score += 5; scoreLog.push('+5 job_title'); }
if (body.message && body.message.length > 50) { score += 10; scoreLog.push('+10 detailed_message'); }
else if (body.message && body.message.length > 10) { score += 5; scoreLog.push('+5 has_message'); }
if (['referral','partner','conference'].includes(body.source)) { score += 15; scoreLog.push('+15 premium_source'); }
else if (['linkedin','google_ads','facebook'].includes(body.source)) { score += 8; scoreLog.push('+8 paid_source'); }
if (body.timeline) { score += 5; scoreLog.push('+5 has_timeline'); }
if (body.team_size && parseInt(body.team_size) > 50) { score += 5; scoreLog.push('+5 large_team'); }

score = Math.min(score, 100);

// --- TIER CLASSIFICATION ---
let tier, priority, sla_minutes, assigned_team;
if (score >= 70) {
  tier = 'ENTERPRISE'; priority = 'P0'; sla_minutes = 60; assigned_team = 'senior_ae';
} else if (score >= 50) {
  tier = 'QUALIFIED'; priority = 'P1'; sla_minutes = 240; assigned_team = 'sales';
} else if (score >= 25) {
  tier = 'NURTURE'; priority = 'P2'; sla_minutes = 1440; assigned_team = 'sdr';
} else {
  tier = 'COLD'; priority = 'P3'; sla_minutes = 4320; assigned_team = 'marketing_auto';
}

return [{ json: {
  // Core data
  lead_id: 'LD-' + Date.now(),
  name: body.name.trim(),
  email: email,
  phone: phone,
  company: body.company || companyGuess,
  job_title: body.job_title || null,
  message: body.message || null,

  // Business context
  budget: budget,
  budget_tier: budgetTier,
  currency: body.currency || 'USD',
  timeline: body.timeline || null,
  team_size: body.team_size || null,
  industry: body.industry || null,

  // Source tracking
  source: body.source || 'direct',
  utm_medium: body.utm_medium || null,
  utm_campaign: body.utm_campaign || null,
  landing_page: body.landing_page || null,

  // Enrichment
  email_domain: domain,
  is_business_email: isBusiness,
  company_from_domain: companyGuess,

  // Scoring
  lead_score: score,
  score_breakdown: scoreLog,
  tier: tier,
  priority: priority,
  sla_minutes: sla_minutes,
  assigned_team: assigned_team,

  // Meta
  warnings: warnings,
  pipeline_version: '3.0',
  ingested_at: new Date().toISOString()
}}];

// Parse AI intent analysis result
const lead = $('2. Validate & Score').first().json;
const raw = $input.first().json;

let intent = {
  intent: 'unknown', intent_confidence: 0,
  pain_points: [], buying_stage: 'unknown', icp_fit: 'unknown'
};

try {
  const content = raw.choices[0].message.content;
  const match = content.match(/\{[\s\S]*\}/);
  if (match) intent = JSON.parse(match[0]);
} catch(e) {
  intent.pain_points = ['ai_parse_error'];
}

return [{ json: { ...lead, ai_intent: intent } }];

