// Parse outreach + merge all data
const lead = $('6. Parse Company Intel').first().json;
const raw = $input.first().json;

let outreach = 'Outreach generation failed. Use standard template.';
try { outreach = raw.choices[0].message.content; } catch(e) {}

return [{ json: {
  ...lead,
  ai_outreach: outreach,
  processing_complete: true,
  total_ai_calls: 3,
  completed_at: new Date().toISOString()
}}];

// QUALIFIED P1 — Standard alert
const d = $input.first().json;
const lines = [
  'QUALIFIED LEAD [P1] | Score: ' + d.lead_score,
  '',
  d.name + (d.company ? ' @ ' + d.company : '') + ' (' + d.email + ')',
  'Intent: ' + d.ai_intent.intent + ' | Stage: ' + d.ai_intent.buying_stage,
  d.budget ? 'Budget: ' + d.currency + ' ' + d.budget.toLocaleString() : '',
  'Pain points: ' + d.ai_intent.pain_points.join(', '),
  '',
  'Suggested outreach:',
  d.ai_outreach.slice(0, 300),
  '',
  'SLA: ' + d.sla_minutes + 'min | Team: ' + d.assigned_team
].filter(Boolean).join('\n');

return [{ json: { ...d, notification: lines, alert_level: 'P1_QUALIFIED' } }];

// NURTURE P2 — Brief log
const d = $input.first().json;
const lines = [
  'NURTURE LEAD [P2] | Score: ' + d.lead_score,
  d.name + ' (' + d.email + ') | Source: ' + d.source,
  'Intent: ' + d.ai_intent.intent + ' | Company type: ' + d.ai_company.company_type,
  'Auto-sequence: nurture_drip'
].join('\n');

return [{ json: { ...d, notification: lines, alert_level: 'P2_NURTURE' } }];

// COLD P3 — Minimal log
const d = $input.first().json;
return [{ json: { ...d, notification: 'COLD [P3]: ' + d.name + ' (' + d.email + ') Score: ' + d.lead_score + ' | Action: cold_reengagement', alert_level: 'P3_COLD' } }];
